import{_ as t,a,b as s}from"./chunks/支持留言.NiGCLVdp.js";import{_ as i,o,c as l,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Other/blog.md","filePath":"ps/Other/blog.md","lastUpdated":1781962217000}'),n={name:"ps/Other/blog.md"};function r(c,e,d,g,h,b){return o(),l("div",null,[...e[0]||(e[0]=[p('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>Blog feature ستاسو ImgBed site ته جلا blog page اضافه کوي.</p><p>له فعالېدو وروسته visitors دا پرانیستلای شي:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+t+'" alt="Blog homepage" loading="lazy"></p><p>blog د open-source <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> project څخه adapted شوی دی. ImgBed دا rewrite او له Vue سره integrate کوي، څو د image hosting site د یوې برخې په توګه وچلېږي.</p><h2 id="چېرته-یې-تنظیم-کړئ" tabindex="-1">چېرته یې تنظیم کړئ <a class="header-anchor" href="#چېرته-یې-تنظیم-کړئ" aria-label="Permalink to &quot;چېرته یې تنظیم کړئ&quot;">​</a></h2><p>Blog settings دلته دي:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+a+'" alt="Blog settings" loading="lazy"></p><h2 id="لومړی-setup" tabindex="-1">لومړی Setup <a class="header-anchor" href="#لومړی-setup" aria-label="Permalink to &quot;لومړی Setup&quot;">​</a></h2><ol><li><code>Enable</code> فعال کړئ.</li><li>هغه GitHub account وټاکئ چې د blog configuration ساتلو لپاره کارېږي.</li><li><code>Update Blog</code> کلیک کړئ.</li><li>د success message تر راتلو انتظار وکړئ.</li><li>د blog کتلو لپاره <code>https://your-domain.com/blog/</code> پرانیزئ.</li></ol><p>په لومړي استعمال کې، ImgBed د ټاکل شوي account لاندې private GitHub repository برابروي:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>دا repository د blog settings او article content ساتي.</p><h2 id="posts-لیکل" tabindex="-1">Posts لیکل <a class="header-anchor" href="#posts-لیکل" aria-label="Permalink to &quot;Posts لیکل&quot;">​</a></h2><p>blog posts په خپل private GitHub repository کې edit کړئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>عادي workflow:</p><ol><li>GitHub پرانیزئ.</li><li>private <code>imgbed-blog-config</code> repository ته لاړ شئ.</li><li>post files edit یا add کړئ.</li><li>changes commit کړئ.</li><li>بېرته ImgBed admin panel ته راشئ او <code>Update Blog</code> کلیک کړئ، یا د blog homepage په چپ پورتني کونج کې logo درې ځله کلیک کړئ څو blog update trigger شي.</li></ol><p><code>Update Blog</code> هغه content نه overwrite کوي چې تاسې لیکلی وي. دا د اړتیا پر وخت repository initialize کوي او blog cache refresh کوي.</p><h2 id="supported-features" tabindex="-1">Supported Features <a class="header-anchor" href="#supported-features" aria-label="Permalink to &quot;Supported Features&quot;">​</a></h2><p>blog عادي blog features ملاتړ کوي، لکه post lists، categories، tags، archives، search، dark mode او language switching.</p><p>comments او visit statistics هم ملاتړ کوي.</p><p><img src="'+s+'" alt="Blog comments" loading="lazy"></p><p>Comments د posts لاندې ښکاري. visitors کولای شي avatar، nickname، email او comment content submit کړي.</p><p>Visit statistics د post views او site visits ښيي، څو د blog traffic ښه درک ولرئ.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>blog تل د <code>/blog/</code> لاندې serve کېږي.</p><p>د بېلګې په توګه، که ستاسو ImgBed domain دا وي:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>blog URL دا دی:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>کله چې blog disabled شي، visitors نور blog page ته access نه شي کولای.</p>',34)])])}const k=i(n,[["render",r]]);export{v as __pageData,k as default};
